final class AuthManager: ObservableObject {
    @AppStorage("isAuthenticated") private var persistedAuthenticated = false

    @Published var isAuthenticated: Bool = false
    @Published var biometricType: LABiometryType = .none
    @Published var errorMessage: String?
    @Published var isAuthenticating = false

    init() {
        isAuthenticated = persistedAuthenticated
        biometricType = currentBiometricType()
    }

    func refreshBiometricType() {
        biometricType = currentBiometricType()
    }

    func signOut() {
        persistedAuthenticated = false
        isAuthenticated = false
        errorMessage = nil
    }

    func loginWithPassword(username: String, password: String) -> Bool {
        let success = !username.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty &&
                      !password.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty

        if success {
            persistedAuthenticated = true
            isAuthenticated = true
            errorMessage = nil
        } else {
            errorMessage = "Please enter a valid username and password."
        }

        return success
    }

    func authenticateWithBiometrics() {
        isAuthenticating = true
        errorMessage = nil

        let context = LAContext()
        context.localizedCancelTitle = "Use Password"
        context.localizedFallbackTitle = "Enter Password"

        var authError: NSError?
        let reason = "Sign in quickly and securely."

        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &authError) {
            biometricType = context.biometryType

            context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { [weak self] success, evaluateError in
                DispatchQueue.main.async {
                    guard let self = self else { return }
                    self.isAuthenticating = false

                    if success {
                        self.persistedAuthenticated = true
                        self.isAuthenticated = true
                        self.errorMessage = nil
                    } else {
                        self.handleBiometricFailure(error: evaluateError)
                    }
                }
            }
        } else {
            biometricType = context.biometryType
            isAuthenticating = false
            handleBiometricUnavailable(error: authError)
        }
    }

    private func currentBiometricType() -> LABiometryType {
        let context = LAContext()
        var error: NSError?
        _ = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
        return context.biometryType
    }

    private func handleBiometricUnavailable(error: Error?) {
        let nsError = error as NSError?

        switch nsError?.code {
        case LAError.biometryNotEnrolled.rawValue:
            errorMessage = "Biometrics are not set up on this device. Please use your password."
        case LAError.biometryNotAvailable.rawValue:
            errorMessage = "Biometric authentication is not available. Please use your password."
        case LAError.biometryLockout.rawValue:
            errorMessage = "Biometrics are locked. Please use your password."
        default:
            errorMessage = "Unable to use biometrics right now. Please try again or enter your password."
        }
    }

    private func handleBiometricFailure(error: Error?) {
        let nsError = error as NSError?

        switch nsError?.code {
        case LAError.authenticationFailed.rawValue:
            errorMessage = "Authentication failed. Please try again or enter your password."
        case LAError.userCancel.rawValue:
            errorMessage = "Authentication was canceled. You can try again or enter your password."
        case LAError.userFallback.rawValue:
            errorMessage = "Please enter your password to continue."
        case LAError.systemCancel.rawValue:
            errorMessage = "Authentication was interrupted. Please try again."
        case LAError.biometryLockout.rawValue:
            errorMessage = "Too many failed attempts. Please enter your password."
        default:
            errorMessage = "Biometric authentication failed. Please try again or enter your password."
        }
    }
}

struct RootView: View {
