                    .opacity(authManager.biometricType == .none ? 0.35 : 1)

                Text("Welcome Back")
                    .font(.largeTitle.bold())

                Text("Use biometrics for quick access, or enter your password.")
                    .font(.subheadline)
                    .foregroundColor(.secondary)
                    .multilineTextAlignment(.center)
                    .padding(.horizontal)

                if let errorMessage = authManager.errorMessage {
                    Text(errorMessage)
                        .font(.footnote)
                        .foregroundColor(.red)
                        .multilineTextAlignment(.center)
                        .padding(.horizontal)
                }

                VStack(spacing: 12) {
                    Button {
                        authManager.authenticateWithBiometrics()
                    } label: {
                        HStack {
                            if authManager.isAuthenticating {
                                ProgressView()
                                    .progressViewStyle(.circular)
                                    .tint(.white)
                            }
                            Text(biometricTitle)
                                .fontWeight(.semibold)
